#include <bits/stdc++.h>
using namespace std;

const int mod=1e9+7;

int n,k,nxt[1<<15][3],p[20],g[20],f[2][1<<15][3],ans[16],ones[1<<15];
char s[20];

void add(int &x,long long y){
    x=(x+y)%mod;
}

int main(){
    scanf("%d%d",&n,&k);
    scanf("%s",s);
    for(int i=0;i<1<<15;i++){
        for(int j=1;j<=k;j++){
            p[j]=p[j-1];
            if((i>>j-1)&1) p[j]++;
        }
        for(int j=1;j<=k;j++){
            g[j]=max(p[j],g[j-1]);
            if(s[j-1]=='N')
                g[j]=p[j-1]+1;
            nxt[i][0]+=(g[j]-g[j-1]<<j-1);
        }
        for(int j=1;j<=k;j++){
            g[j]=max(p[j],g[j-1]);
            if(s[j-1]=='O')
                g[j]=p[j-1]+1;
            nxt[i][1]+=(g[j]-g[j-1]<<j-1);
        }
        for(int j=1;j<=k;j++){
            g[j]=max(p[j],g[j-1]);
            if(s[j-1]=='I')
                g[j]=p[j-1]+1;
            nxt[i][2]+=(g[j]-g[j-1]<<j-1);
        }
    }
    f[0][0][0]=1;
    for(int i=0,xs=0;i<n;i++,xs^=1){
        for(int j=0;j<1<<k;j++){
            add(f[!xs][nxt[j][0]][1],f[xs][j][0]);
            add(f[!xs][nxt[j][1]][0],f[xs][j][0]);
            add(f[!xs][nxt[j][2]][0],f[xs][j][0]);
            add(f[!xs][nxt[j][0]][1],f[xs][j][1]);
            add(f[!xs][nxt[j][1]][2],f[xs][j][1]);
            add(f[!xs][nxt[j][2]][0],f[xs][j][1]);
            add(f[!xs][nxt[j][0]][1],f[xs][j][2]);
            add(f[!xs][nxt[j][1]][0],f[xs][j][2]);
        }
        memset(f[xs],0,sizeof(f[xs]));
    }
    for(int i=0;i<1<<15;i++){
        if(i) ones[i]=ones[i-(i&(-i))]+1;
        add(ans[ones[i]],1ll*f[n&1][i][0]+f[n&1][i][1]+f[n&1][i][2]);
    }
    for(int i=0;i<=k;i++)
        printf("%d\n",ans[i]);
    return 0;
}
